import org.junit.jupiter.api.Test;

public class SemanticLivenessAnalyzerTest {

	@Test
	public void dropsUnusedDefinitionsButKeepsMinusWitnessesLive() throws Exception {
		StatementPattern base = pattern("x", "baseOnly");
		Extension extension = new Extension(base,
				new ExtensionElem(new ValueConstant(SimpleValueFactory.getInstance().createLiteral(1)), "unused"));
		Projection projection = new Projection(extension, new ProjectionElemList(new ProjectionElem("x")), false);
		QueryRoot root = new QueryRoot(projection);
		Object liveness = liveness(ScopeAnalysis.analyze(root), root);
		assertThat(isLive(liveness, extension, "x")).isTrue();
		assertThat(isLive(liveness, extension, "unused")).isFalse();

		Difference minus = new Difference(pattern("x", "leftOnly"), pattern("x", "rightWitness"));
		QueryRoot minusRoot = new QueryRoot(minus);
		Object minusLiveness = liveness(ScopeAnalysis.analyze(minusRoot), minusRoot);
		assertThat(isLive(minusLiveness, minus.getRightArg(), "rightWitness")).isTrue();
	}

	private static StatementPattern pattern(String first, String second) {
		return new StatementPattern(Var.of(first),
				Var.of("_p", SimpleValueFactory.getInstance().createIRI("urn:p")), Var.of(second));
	}

	private static Object liveness(ScopeAnalysis analysis, QueryModelNode root) throws Exception {
		Class<?> type = Class.forName(
				"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope.SemanticLivenessAnalyzer");
		Constructor<?> constructor = type.getDeclaredConstructor(ScopeAnalysis.class);
		constructor.setAccessible(true);
		Object result = constructor.newInstance(analysis);
		Method analyze = type.getDeclaredMethod("analyze", QueryModelNode.class);
		analyze.setAccessible(true);
		analyze.invoke(result, root);
		return result;
	}

	private static boolean isLive(Object liveness, QueryModelNode node, String name) throws Exception {
		Method method = liveness.getClass().getDeclaredMethod("isLive", QueryModelNode.class, String.class);
		method.setAccessible(true);
		return (boolean) method.invoke(liveness, node, name);
	}
}
